/**
 * Marker stored in Generation.provider (and .model) for assets the user
 * uploaded locally (not generated by an AI provider). Lets the asset
 * browser surface a dedicated "Local assets" section without a schema
 * change, and lets billing / usage code skip these rows.
 */
export const USER_UPLOAD_PROVIDER = 'user-upload'

/**
 * Server-side business cap: a stored user-upload's decoded image may not
 * exceed this (5 MB). Enforced in `upload-image.service`. NOT a safe
 * client-side compression target — see `CLIENT_UPLOAD_MAX_BYTES`.
 */
export const USER_UPLOAD_MAX_BYTES = 5 * 1024 * 1024

/**
 * Client-side compression cap for images sent to the server as a base64 data
 * URL in the request body. Vercel caps a Serverless Function request body at
 * ~4.5 MB and base64 inflates bytes by ~33%, so the pre-encode file must stay
 * well under that: 3 MB → ~4.1 MB base64, leaving headroom for the JSON
 * envelope. Every client upload that inlines a data URL must compress to this
 * first, or large images 413 at the platform before reaching the handler.
 * (Raising this requires presigned direct-to-R2 uploads to bypass the limit.)
 */
export const CLIENT_UPLOAD_MAX_BYTES = 3 * 1024 * 1024

/**
 * Accepted MIME types for user uploads. Deliberately narrow — `image/svg+xml`
 * is excluded because SVG can carry inline scripts that execute when the
 * file is later opened directly from the CDN.
 *
 * Server-side, the *real* format is re-verified against the buffer via
 * `sharp.metadata()` in `upload-image.service.ts` so a client can't lie
 * about the MIME type in the data URL header.
 */
export const USER_UPLOAD_ACCEPTED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/gif',
] as const

export type AcceptedUploadMimeType =
  (typeof USER_UPLOAD_ACCEPTED_MIME_TYPES)[number]

/**
 * `sharp.metadata().format` values that correspond to the allowed MIME
 * types above. Used by `upload-image.service.ts` for magic-byte validation.
 */
export const USER_UPLOAD_ACCEPTED_SHARP_FORMATS = new Set([
  'jpeg',
  'png',
  'webp',
  'gif',
])
